  ('dietitian-moex-08434', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '營養教育理論可分成個人、人際以及社區三個層面，請問下列何種理論模式屬於個人層面？', '["Social cognitive theory", "Diffusion of innovation", "Health belief model", "PRECEDE-PROCEED model"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08435', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在參加過一項體重控制活動後，張小姐評估自己能在春節期間，以均衡飲食的觀念，選擇低熱量且均衡 營養的飲食行為。此種情形稱為：', '["自我效能", "自我控制", "自我評估", "自我解放"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08436', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據1999－2000台灣地區老人營養健康狀況調查資料顯示，老人飲食營養知識欠佳，其中又以那方面的 知識最為缺乏？', '["疾病與飲食營養的關係", "食物的需要性", "食物與營養含量比較", "保健營養食品"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08437', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '目前國民中、小學校內販售食品之規範，主要根據教育部及行政院衛生署於民國94年公布之：', '["學校衛生法", "健康食品法", "校園飲品及點心販售範圍", "學校餐廳廚房員生消費合作社衛生管理辦法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08438', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '營養師法規定，營養諮詢機構之申請人應曾在教學醫院或營養諮詢機構執行營養師業務多少年以上？', '["6個月", "1年", "2年", "3年"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
