  ('dietitian-moex-08440', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '政府為降低成人肥胖比率，於民國92年訂定一項5年計畫，該計畫之名稱為：', '["聰明減重，健康沒煩惱", "苗條體態，健康跟著來", "輕鬆減重，大家一起來", "成人健康體位，挑戰1824"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
